+    private func determineChatLaunchStrategy(capabilities: TerminalCapabilities) -> ChatLaunchStrategy {
+        if self.chat {
+            return .interactive(initialPrompt: self.normalizedTaskInput)
+        }
+
+        if self.hasTaskInput || self.listSessions {
+            return .none
+        }
+
